{
  "name": "Cyberhound: The Deal Sniffer",
  "description": "A futuristic AI-powered cyber-hound that tracks down the best free trials, discounts, and internet deals using real-time web grounding."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Deal {
  id: string;
  title: string;
  description: string;
  category: 'Free Trial' | 'Discount' | 'Coupon' | 'Limited Time';
  link: string;
  source: string;
  relevanceScore: number;
}

export interface SniffResult {
  text: string;
  deals: Deal[];
  sources: { title: string; uri: string }[];
}

export enum HoundMood {
  IDLE = 'idle',
  SNIFFING = 'sniffing',
  HAPPY = 'happy',
  TIRED = 'tired'
}

import { GoogleGenAI, Type } from "@google/genai";
import { SniffResult, Deal } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const sniffDeals = async (query: string): Promise<SniffResult> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Search for the best internet deals, free trials, and discounts for: ${query}. 
      Focus on active offers and list them clearly.`,
      config: {
        tools: [{ googleSearch: {} }],
        // We aren't using responseSchema here because googleSearch tools don't support it yet
        // but we will parse the output or ask for a specific format.
      },
    });

    const text = response.text || "I couldn't sniff out anything specific right now. Bark!";
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || "Source",
      uri: chunk.web?.uri || "#"
    })) || [];

    // Heuristic: Extract potential deals from the text response
    // For a production app, we might do a second pass to structure this, 
    // but here we will provide the formatted text and the sources.

    return {
      text,
      deals: [], // Handled by manual parsing or direct display of text
      sources
    };
  } catch (error) {
    console.error("Sniffing error:", error);
    throw error;
  }
};

import React from 'react';
import { HoundMood } from '../types';

interface MascotProps {
  mood: HoundMood;
}

export const CyberhoundMascot: React.FC<MascotProps> = ({ mood }) => {
  const isSniffing = mood === HoundMood.SNIFFING;

  return (
    <div className={`relative w-48 h-48 transition-all duration-300 ${isSniffing ? 'bark-animation' : ''}`}>
      <svg viewBox="0 0 200 200" className="w-full h-full drop-shadow-[0_0_10px_rgba(34,211,238,0.5)]">
        {/* Hound Head */}
        <path 
          d="M40,100 Q40,40 100,40 Q160,40 160,100 L160,140 Q160,160 140,160 L60,160 Q40,160 40,140 Z" 
          fill="none" 
          stroke="#22d3ee" 
          strokeWidth="4"
          className={isSniffing ? 'animate-pulse' : ''}
        />

        {/* Ears */}
        <path d="M40,70 L20,40 L60,60" fill="none" stroke="#22d3ee" strokeWidth="4" />
        <path d="M160,70 L180,40 L140,60" fill="none" stroke="#22d3ee" strokeWidth="4" />

        {/* Eyes - Cybernetic */}
        <circle cx="75" cy="90" r="8" fill={isSniffing ? "#ef4444" : "#22d3ee"} />
        <circle cx="125" cy="90" r="8" fill={isSniffing ? "#ef4444" : "#22d3ee"} />
        <rect x="65" y="85" width="20" height="2" fill="#000" opacity="0.3" />
        <rect x="115" y="85" width="20" height="2" fill="#000" opacity="0.3" />

        {/* Nose */}
        <path 
          d="M90,120 L110,120 L100,135 Z" 
          fill="#22d3ee" 
          className={isSniffing ? 'animate-bounce' : ''}
        />

        {/* Mouth/Jaw */}
        <path 
          d={isSniffing ? "M80,145 Q100,160 120,145" : "M80,145 Q100,150 120,145"} 
          fill="none" 
          stroke="#22d3ee" 
          strokeWidth="3" 
        />

        {/* Cyber Detail */}
        <path d="M100,40 L100,20 M60,160 L60,180 M140,160 L140,180" stroke="#22d3ee" strokeWidth="2" opacity="0.5" />
      </svg>

      {/* Radar Effect for Sniffing */}
      {isSniffing && (
        <div className="absolute inset-0 border-4 border-cyan-500 rounded-full animate-ping opacity-20"></div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Search, Zap } from 'lucide-react';

interface SearchInterfaceProps {
  onSearch: (query: string) => void;
  isLoading: boolean;
}

export const SearchInterface: React.FC<SearchInterfaceProps> = ({ onSearch, isLoading }) => {
  const [query, setQuery] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (query.trim()) {
      onSearch(query);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="w-full max-w-2xl group">
      <div className="relative flex items-center">
        <div className="absolute left-4 text-cyan-500 group-focus-within:text-cyan-400">
          <Search size={24} />
        </div>
        <input
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="What should I sniff out? (e.g. VPN discounts, Game trials...)"
          disabled={isLoading}
          className="w-full bg-black/40 border-2 border-cyan-900/50 rounded-2xl py-5 pl-14 pr-32 text-xl focus:outline-none focus:border-cyan-500 transition-all placeholder:text-cyan-900/60 font-medium"
        />
        <button
          type="submit"
          disabled={isLoading || !query.trim()}
          className="absolute right-3 bg-cyan-600 hover:bg-cyan-500 disabled:bg-cyan-900 text-black px-6 py-2.5 rounded-xl font-bold flex items-center gap-2 transition-colors"
        >
          {isLoading ? (
            <div className="w-5 h-5 border-2 border-black border-t-transparent rounded-full animate-spin"></div>
          ) : (
            <>
              <Zap size={18} />
              SNIFF
            </>
          )}
        </button>
      </div>
    </form>
  );
};

import React from 'react';
import { ExternalLink, Tag, Globe, CheckCircle2 } from 'lucide-react';
import { SniffResult } from '../types';

interface ResultDisplayProps {
  result: SniffResult;
}

export const ResultDisplay: React.FC<ResultDisplayProps> = ({ result }) => {
  // Simple markdown renderer for the response text
  const formatText = (text: string) => {
    return text.split('\n').map((line, i) => (
      <p key={i} className="mb-4 leading-relaxed text-gray-300">
        {line}
      </p>
    ));
  };

  return (
    <div className="w-full max-w-4xl animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">

        {/* Main findings */}
        <div className="md:col-span-2 space-y-6">
          <div className="bg-cyan-950/20 border border-cyan-800/30 rounded-3xl p-8 backdrop-blur-sm relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4 opacity-10">
              <Tag size={120} />
            </div>
            <h2 className="text-2xl font-bold text-cyan-400 mb-6 flex items-center gap-3">
              <CheckCircle2 className="text-cyan-500" />
              Scent Detected!
            </h2>
            <div className="prose prose-invert max-w-none">
              {formatText(result.text)}
            </div>
          </div>
        </div>

        {/* Sources/Grounding */}
        <div className="space-y-6">
          <div className="bg-black/40 border border-cyan-900/30 rounded-3xl p-6 h-fit">
            <h3 className="text-sm font-bold text-cyan-600 uppercase tracking-widest mb-4 flex items-center gap-2">
              <Globe size={16} />
              Sources Tracked
            </h3>
            <div className="space-y-3">
              {result.sources.length > 0 ? (
                result.sources.map((source, idx) => (
                  <a
                    key={idx}
                    href={source.uri}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="flex items-start justify-between gap-3 p-3 rounded-xl bg-cyan-900/10 hover:bg-cyan-900/30 border border-cyan-800/20 transition-all group"
                  >
                    <span className="text-sm text-gray-400 line-clamp-2 group-hover:text-cyan-300 transition-colors">
                      {source.title}
                    </span>
                    <ExternalLink size={14} className="text-cyan-600 shrink-0 mt-1" />
                  </a>
                ))
              ) : (
                <p className="text-xs text-gray-600 italic">No external links verified for this scent.</p>
              )}
            </div>
          </div>

          <div className="bg-gradient-to-br from-cyan-900/20 to-purple-900/20 border border-cyan-800/30 rounded-3xl p-6">
            <p className="text-xs text-cyan-600 leading-tight">
              CYBERHOUND TIP: Always double-check expiration dates before committing. These deals are sniffed live but may expire as fast as they appeared.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { CyberhoundMascot } from './components/CyberhoundMascot';
import { SearchInterface } from './components/SearchInterface';
import { ResultDisplay } from './components/ResultDisplay';
import { sniffDeals } from './services/geminiService';
import { SniffResult, HoundMood } from './types';
import { Ghost, ShieldAlert, Zap, History, Sparkles } from 'lucide-react';

const App: React.FC = () => {
  const [mood, setMood] = useState<HoundMood>(HoundMood.IDLE);
  const [result, setResult] = useState<SniffResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [history, setHistory] = useState<string[]>([]);

  const handleSniff = async (query: string) => {
    setIsLoading(true);
    setError(null);
    setMood(HoundMood.SNIFFING);
    setResult(null);

    try {
      const data = await sniffDeals(query);
      setResult(data);
      setMood(HoundMood.HAPPY);
      setHistory(prev => [query, ...prev.slice(0, 4)]);
    } catch (err) {
      setError("The trail went cold... (API Error)");
      setMood(HoundMood.TIRED);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen relative overflow-hidden flex flex-col items-center cyber-grid">
      <div className="scanline"></div>

      {/* Background Glows */}
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-cyan-900/20 blur-[120px] rounded-full"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-900/10 blur-[120px] rounded-full"></div>

      {/* Navigation Header */}
      <header className="w-full px-8 py-6 flex justify-between items-center z-10">
        <div className="flex items-center gap-3">
          <div className="bg-cyan-500 p-2 rounded-lg text-black">
            <Zap size={24} />
          </div>
          <h1 className="text-2xl font-black tracking-tighter neon-text">
            CYBER<span className="text-cyan-500">HOUND</span>
          </h1>
        </div>
        <div className="flex gap-4">
          <button className="hidden md:flex items-center gap-2 text-sm font-bold text-cyan-600 hover:text-cyan-400 transition-colors uppercase tracking-widest border border-cyan-900/50 px-4 py-2 rounded-full">
            <History size={16} /> History
          </button>
          <div className="h-10 w-10 rounded-full border-2 border-cyan-500 flex items-center justify-center overflow-hidden bg-black">
            <img src="https://picsum.photos/id/237/100/100" alt="Avatar" className="w-full h-full object-cover" />
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 w-full max-w-6xl flex flex-col items-center px-6 py-12 z-10">

        {/* Mascot & Intro */}
        <div className="flex flex-col items-center text-center mb-12">
          <CyberhoundMascot mood={mood} />
          <div className="mt-8 space-y-2">
            <h2 className="text-4xl md:text-5xl font-black text-white">
              Sniffing out the web's best <span className="text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 to-blue-500 italic">Deals</span>
            </h2>
            <p className="text-gray-500 text-lg max-w-md mx-auto">
              Real-time discounts, free trials, and promo codes powered by neural scent tracking.
            </p>
          </div>
        </div>

        {/* Search Bar */}
        <div className="w-full flex justify-center mb-16">
          <SearchInterface onSearch={handleSniff} isLoading={isLoading} />
        </div>

        {/* Dynamic States */}
        {isLoading && (
          <div className="flex flex-col items-center gap-4 text-cyan-500 animate-pulse">
            <p className="mono text-sm tracking-[0.2em] font-bold">SCANNING_WEB_PROTOCOLS...</p>
            <div className="flex gap-1">
              {[0, 1, 2, 3].map(i => (
                <div key={i} className="w-2 h-2 bg-cyan-500 rounded-full animate-bounce" style={{ animationDelay: `${i * 0.1}s` }}></div>
              ))}
            </div>
          </div>
        )}

        {error && (
          <div className="flex flex-col items-center gap-4 bg-red-950/20 border border-red-900/50 p-6 rounded-2xl max-w-md text-center">
            <ShieldAlert size={48} className="text-red-500" />
            <p className="text-red-200 font-bold">{error}</p>
            <button onClick={() => setMood(HoundMood.IDLE)} className="text-red-400 underline text-sm">Clear Error</button>
          </div>
        )}

        {result && <ResultDisplay result={result} />}

        {/* Idle Suggestions */}
        {!result && !isLoading && !error && (
          <div className="w-full max-w-2xl grid grid-cols-2 md:grid-cols-4 gap-4 mt-8 opacity-60 hover:opacity-100 transition-opacity">
            {['VPN Free Trials', 'Steam Discounts', 'Nike Promos', 'Cloud Credits'].map(tag => (
              <button 
                key={tag}
                onClick={() => handleSniff(tag)}
                className="bg-cyan-950/20 border border-cyan-800/30 rounded-xl py-3 px-4 text-sm text-cyan-400 hover:bg-cyan-500 hover:text-black hover:border-cyan-500 transition-all flex items-center justify-center gap-2 group"
              >
                <Sparkles size={14} className="group-hover:rotate-12 transition-transform" />
                {tag}
              </button>
            ))}
          </div>
        )}
      </main>

      {/* Footer Content */}
      <footer className="w-full max-w-6xl px-8 py-12 border-t border-cyan-900/30 mt-20 flex flex-col md:flex-row justify-between items-center gap-8 text-gray-500 text-sm">
        <div className="flex items-center gap-4">
          <span className="mono text-cyan-800">SYSTEM_STATUS: NOMINAL</span>
          <span className="mono text-cyan-800">NODE: HOUND-01</span>
        </div>
        <p>© 2024 CYBERHOUND LABS. ALL TRAILS TRACKED.</p>
        <div className="flex gap-6">
          <a href="#" className="hover:text-cyan-400 transition-colors">Privacy API</a>
          <a href="#" className="hover:text-cyan-400 transition-colors">Scent Protocol</a>
        </div>
      </footer>
    </div>
  );
};

export default App;
